  1→package testutil
  2→
  3→import (
  4→	"crypto/sha256"
  5→	"encoding/hex"
  6→	"encoding/json"
  7→	"fmt"
  8→	"os"
  9→	"path/filepath"
 10→	"regexp"
 11→	"strings"
 12→	"testing"
 13→	"time"
 14→
 15→	"github.com/stretchr/testify/assert"
 16→	"github.com/stretchr/testify/require"
 17→)
 18→
 19→// DeepCheckpointValidation contains expected values for comprehensive checkpoint validation.
 20→type DeepCheckpointValidation struct {
 21→	CheckpointID              string
 22→	Strategy                  string
 23→	FilesTouched              []string
 24→	ExpectedPrompts           []string
 25→	ExpectedTranscriptContent []string
 26→}
 27→
 28→var hexIDPattern = regexp.MustCompile(`^[0-9a-f]{12}$`)
 29→
 30→// AssertFileExists asserts that at least one file matches the glob pattern
 31→// relative to dir.
 32→func AssertFileExists(t *testing.T, dir string, glob string) {
 33→	t.Helper()
 34→	matches, err := filepath.Glob(filepath.Join(dir, glob))
 35→	require.NoError(t, err)
 36→	assert.NotEmpty(t, matches, "expected files matching %s in %s", glob, dir)
 37→}
 38→
 39→// WaitForFileExists polls until at least one file matches the glob pattern
 40→// relative to dir, or fails the test after timeout.
 41→func WaitForFileExists(t *testing.T, dir string, glob string, timeout time.Duration) {
 42→	t.Helper()
 43→	pattern := filepath.Join(dir, glob)
 44→	deadline := time.Now().Add(timeout)
 45→	for {
 46→		matches, err := filepath.Glob(pattern)
 47→		require.NoError(t, err)
 48→		if len(matches) > 0 {
 49→			return
 50→		}
 51→		if time.Now().After(deadline) {
 52→			t.Fatalf("expected files matching %s in %s within %s", glob, dir, timeout)
 53→		}
 54→		time.Sleep(500 * time.Millisecond)
 55→	}
 56→}
 57→
 58→// AssertNewCommits polls until at least `atLeast` new commits exist since setup,
 59→// or fails after 20 seconds.
 60→func AssertNewCommits(t *testing.T, s *RepoState, atLeast int) {
 61→	t.Helper()
 62→	deadline := time.Now().Add(20 * time.Second)
 63→	for {
 64→		out := GitOutput(t, s.Dir, "log", "--oneline", s.HeadBefore+"..HEAD")
 65→		var lines []string
 66→		if out != "" {
 67→			lines = strings.Split(strings.TrimSpace(out), "\n")
 68→		}
 69→		if len(lines) >= atLeast {
 70→			return
 71→		}
 72→		if time.Now().After(deadline) {
 73→			t.Fatalf("expected at least %d new commit(s), got %d after 20s", atLeast, len(lines))
 74→		}
 75→		time.Sleep(500 * time.Millisecond)
 76→	}
 77→}
 78→
 79→// WaitForCheckpoint polls until the checkpoint branch advances from its
 80→// initial state, or fails the test after timeout.
 81→func WaitForCheckpoint(t *testing.T, s *RepoState, timeout time.Duration) {
 82→	t.Helper()
 83→	deadline := time.Now().Add(timeout)
 84→	for time.Now().Before(deadline) {
 85→		after := GitOutput(t, s.Dir, "rev-parse", "entire/checkpoints/v1")
 86→		if after != s.CheckpointBefore {
 87→			return
 88→		}
 89→		time.Sleep(200 * time.Millisecond)
 90→	}
 91→	t.Fatalf("checkpoint branch did not advance within %s", timeout)
 92→}
 93→
 94→// WaitForCheckpointAdvanceFrom polls until the checkpoint branch advances from
 95→// the given ref, or fails the test after timeout.
 96→func WaitForCheckpointAdvanceFrom(t *testing.T, dir string, fromRef string, timeout time.Duration) {
 97→	t.Helper()
 98→	deadline := time.Now().Add(timeout)
 99→	for time.Now().Before(deadline) {
100→		after := GitOutput(t, dir, "rev-parse", "entire/checkpoints/v1")
101→		if after != fromRef {
102→			return
103→		}
104→		time.Sleep(200 * time.Millisecond)
105→	}
106→	t.Fatalf("checkpoint branch did not advance from %s within %s", fromRef[:8], timeout)
107→}
108→
109→// AssertCheckpointAdvanced asserts the checkpoint branch moved forward.
110→func AssertCheckpointAdvanced(t *testing.T, s *RepoState) {
111→	t.Helper()
112→	after := GitOutput(t, s.Dir, "rev-parse", "entire/checkpoints/v1")
113→	assert.NotEqual(t, s.CheckpointBefore, after, "checkpoint branch did not advance")
114→}
115→
116→// AssertCheckpointNotAdvanced asserts the checkpoint branch has NOT moved.
117→func AssertCheckpointNotAdvanced(t *testing.T, s *RepoState) {
118→	t.Helper()
119→	after := GitOutput(t, s.Dir, "rev-parse", "entire/checkpoints/v1")
120→	assert.Equal(t, s.CheckpointBefore, after, "checkpoint branch advanced unexpectedly")
121→}
122→
123→// AssertCheckpointIDFormat asserts the checkpoint ID is 12 lowercase hex chars.
124→func AssertCheckpointIDFormat(t *testing.T, checkpointID string) {
125→	t.Helper()
126→	assert.Regexp(t, hexIDPattern, checkpointID,
127→		"checkpoint ID %q should be 12 lowercase hex chars", checkpointID)
128→}
129→
130→// AssertHasCheckpointTrailer asserts the commit has an Entire-Checkpoint trailer,
131→// validates its format, and returns its value.
132→func AssertHasCheckpointTrailer(t *testing.T, dir string, ref string) string {
133→	t.Helper()
134→	trailer := GetCheckpointTrailer(t, dir, ref)
135→	require.NotEmpty(t, trailer, "no Entire-Checkpoint trailer on %s", ref)
136→	AssertCheckpointIDFormat(t, trailer)
137→	return trailer
138→}
139→
140→// AssertNoCheckpointTrailer asserts the commit does NOT have an Entire-Checkpoint trailer.
141→func AssertNoCheckpointTrailer(t *testing.T, dir string, ref string) {
142→	t.Helper()
143→	trailer := GetCheckpointTrailer(t, dir, ref)
144→	assert.Empty(t, trailer, "expected no Entire-Checkpoint trailer on %s, got %q", ref, trailer)
145→}
146→
147→// AssertCheckpointExists asserts that the checkpoint ID is mentioned on
148→// the checkpoint branch and that its metadata.json exists in the tree.
149→func AssertCheckpointExists(t *testing.T, dir string, checkpointID string) {
150→	t.Helper()
151→	out := GitOutput(t, dir, "log", "entire/checkpoints/v1", "--grep="+checkpointID, "--oneline")
152→	assert.NotEmpty(t, out, "checkpoint %s not found on checkpoint branch", checkpointID)
153→
154→	path := CheckpointPath(checkpointID) + "/metadata.json"
155→	blob := "entire/checkpoints/v1:" + path
156→	raw := gitOutputSafe(dir, "show", blob)
157→	assert.NotEmpty(t, raw,
158→		"checkpoint %s metadata not found at %s", checkpointID, path)
159→}
160→
161→// AssertCommitLinkedToCheckpoint asserts the trailer exists AND the
162→// checkpoint data exists on the checkpoint branch.
163→func AssertCommitLinkedToCheckpoint(t *testing.T, dir string, ref string) {
164→	t.Helper()
165→	trailer := AssertHasCheckpointTrailer(t, dir, ref)
166→	AssertCheckpointExists(t, dir, trailer)
167→}
168→
169→// AssertCheckpointHasSingleSession asserts checkpoint metadata has exactly one session.
170→func AssertCheckpointHasSingleSession(t *testing.T, dir string, checkpointID string) {
171→	t.Helper()
172→	meta := ReadCheckpointMetadata(t, dir, checkpointID)
173→	assert.Len(t, meta.Sessions, 1,
174→		"expected 1 session in checkpoint %s, got %d", checkpointID, len(meta.Sessions))
175→}
176→
177→// AssertCheckpointMetadataComplete asserts essential fields in checkpoint metadata are populated.
